fn rbtdro_onboarding_conclave_reliquary(dir: &Path) -> rbtdre_Verdict {
    let probe = rbtdrb_Probe {
        name: "governor RBRA present",
        check: rbtdro_probe_governor_rbra,
        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
    };
    if let Err(v) = rbtdrb_assert(&probe) {
        return v;
    }
    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_conclave_reliquary_impl(ctx, dir))
}

fn rbtdro_onboarding_conclave_reliquary_impl(
    ctx: &mut rbtdri_Context,
    dir: &Path,
) -> rbtdre_Verdict {
    let root = ctx.project_root().to_path_buf();
    let result = match rbtdro_invoke_or_fail(
        ctx,
        "conclave",
        "",
        RBTDGC_CONCLAVE_RELIQUARY,
        &[],
        &[],
        dir,
        "conclave",
    ) {
        Ok(r) => r,
        Err(v) => return v,
    };

    let stamp = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_RELIQUARY) {
        Ok(s) => s,
        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary fact: {}", e)),
    };
    let _ = std::fs::write(dir.join("reliquary-stamp.txt"), &stamp);

    // Wildcard-yoke: single invocation writes RBRV_RELIQUARY into every
    // vessel under ${RBRR_VESSEL_DIR}.
    if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, RBTDGC_VERB_YOKE) {
        return v;
    }

    // Commit the rbrv.env changes for all yoked vessels — the wildcard yoke
    // rewrites every vessel's rbrv.env, so stage that enumerated set.
    let yoked = match rbtdro_all_vessel_rbrv_paths(&root) {
        Ok(p) => p,
        Err(e) => return rbtdre_Verdict::Fail(format!("enumerate vessel rbrv.env set: {}", e)),
    };
    if let Err(v) = rbtdro_git_commit(
        &yoked,
        &format!(
            "conclave-reliquary: {} stamp across all vessels",
            RBTDGC_VERB_YOKE
        ),
    ) {
        return v;
    }

    rbtdre_Verdict::Pass
}

