/// Resolve a suite name to its registered Suite definition. Returns None for
/// unregistered names; callers decide whether that is fatal.
pub fn rbtdrc_lookup_suite(suite: &str) -> Option<&'static rbtdre_Suite> {
    RBTDRC_SUITES.iter().find(|s| s.name == suite)
}

/// A fixture is credless-tier iff it is a member of the fast suite — suite
/// composition is the single source of truth, so there is no second
/// declaration to drift. For credless fixtures, in ANY suite that embeds
/// them, the invocation layer exports RBGO_CREDLESS=1 and the bash token
/// mints (rbgo_get_token_capture, zrbgp_refresh_capture) refuse — making
/// fast-tier credlessness structural rather than conventional.
pub(crate) fn rbtdrc_fixture_is_credless(fixture_name: &str) -> bool {
    rbtdrc_lookup_suite(RBTDRC_SUITE_NAME_FAST)
        .map(|s| s.fixtures.iter().any(|f| f.name == fixture_name))
        .unwrap_or(false)
}

